use std::sync::atomic::{AtomicI64, Ordering};
use std::sync::Mutex;

struct SensorStats {
    count: AtomicI64,
    sum: AtomicI64,
}

impl SensorStats {
    fn new() -> Self {
        SensorStats {
            count: AtomicI64::new(0),
            sum: AtomicI64::new(0),
        }
    }

    fn record_reading(&self, value: i64) {
        self.count.fetch_add(1, Ordering::SeqCst);
        self.sum.fetch_add(value, Ordering::SeqCst);
    }

    fn get_mean(&self) -> Option<f64> {
        let count = self.count.load(Ordering::SeqCst);
        if count == 0 {
            return None;
        }
        let sum = self.sum.load(Ordering::SeqCst);
        Some(sum as f64 / count as f64)
    }

    fn get_current_state(&self) -> (i64, i64) {
        (self.count.load(Ordering::SeqCst), self.sum.load(Ordering::SeqCst))
    }
}

struct DataStreamer {
    stats: Mutex<SensorStats>,
}

impl DataStreamer {
    fn new() -> Self {
        DataStreamer { stats: Mutex::new(SensorStats::new()) }
    }

    fn process_data(&self, data_points: &[i64]) {
        let mut stats = self.stats.lock().unwrap();
        for &point in data_points {
            stats.record_reading(point);
        }
    }

    fn calculate_statistics(&self) -> Option<f64> {
        let stats = self.stats.lock().unwrap();
        stats.get_mean()
    }
}

fn main() {
    let streamer = DataStreamer::new();
    println!("Starting data simulation...");

    let batch1 = vec![10, 20, 30];
    streamer.process_data(&batch1);
    if let Some(mean) = streamer.calculate_statistics() {
        println!("After Batch 1: Mean is {:.2}", mean);
    }

    let batch2 = vec![5, 15];
    streamer.process_data(&batch2);
    if let Some(mean) = streamer.calculate_statistics() {
        println!("After Batch 2: Mean is {:.2}", mean);
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct ChatRoom {
    id: String,
    user_list: Arc<Mutex<HashMap<String, u32>>>,
}

impl ChatRoom {
    fn new(room_id: String) -> Self {
        ChatRoom {
            id: room_id,
            user_list: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn add_user(&self, username: String) -> Result<(), String> {
        let mut users = self.user_list.lock().unwrap();
        if users.contains_key(&username) {
            return Err(format!("User {} already in room {}", username, self.id));
        }
        users.insert(username, 1);
        Ok(())
    }

    fn broadcast_message(&self, message: &str) -> Result<usize, String> {
        let users = self.user_list.lock().unwrap();
        if users.is_empty() {
            return Err(format!("Cannot broadcast, room {} has no connected users.", self.id));
        }
        println!("[Broadcast in {}] {}", self.id, message);
        Ok(users.len())
    }
}

struct ChatServer {
    rooms: Mutex<HashMap<String, Arc<ChatRoom>>>,
}

impl ChatServer {
    fn new() -> Self {
        ChatServer { rooms: Mutex::new(HashMap::new()) }
    }

    fn get_or_create_room(&self, room_id: &str) -> Arc<ChatRoom> {
        let mut rooms = self.rooms.lock().unwrap();
        if let Some(room) = rooms.get(room_id).cloned() {
            return room;
        }
        let new_room = Arc::new(ChatRoom::new(String::from(room_id)));
        rooms.insert(String::from(room_id), new_room.clone());
        new_room
    }
}

fn main() {
    let server = ChatServer::new();
    let room_a = server.get_or_create_room("General");

    match room_a.add_user(String::from("Alice")) {
        Ok(_) => println!("Successfully added Alice."),
        Err(e) => eprintln!("Error adding user: {}", e) 
    }

    match room_a.add_user(String::from("Bob")) {
        Ok(_) => println!("Successfully added Bob."),
        Err(e) => eprintln!("Error adding user: {}", e)
    }

    if let Ok(count) = room_a.broadcast_message(&String::from("Hey everyone, this is a test!")) {
        println!("Message successfully sent to {} users.", count);
    } else { 
        eprintln!("Failed to broadcast message.");
    }
}

use std::io::{self, BufReader, BufRead, Write};
use std::process;

fn main() -> io::Result<()> {
    let stdin = io::stdin();
    let reader = BufReader::new(stdin.lock());
    let mut lines_processed = 0;
    let mut lines_written = 0;

    let filter_string = "ERROR";

    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => continue,
        };
        lines_processed += 1;

        if line.contains(filter_string) {
            println!("{}", &line);
            lines_written += 1;
        }
    }

    eprintln!("Finished processing stream. Total lines read: {}", lines_processed);
    eprintln!("Total matching lines written to stdout: {}", lines_written);

    Ok(())
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Mutex;

struct PlayerState {
    health: i32,
    is_active: bool,
}
impl PlayerState {
    fn new(health: i32) -> Self {
        PlayerState { health, is_active: true }
    }
}

struct GameRecorder {
    state: Mutex<PlayerState>,
    is_recording: AtomicBool,
}
impl GameRecorder {
    fn new(initial_health: i32) -> Self {
        GameRecorder {
            state: Mutex::new(PlayerState::new(initial_health)),
            is_recording: AtomicBool::new(false),
        }
    }

    fn start_recording(&self) -> Result<(), &'static str> {
        if self.is_recording.load(Ordering::SeqCst) {
            return Err("Already recording!");
        }
        self.is_recording.store(true, Ordering::SeqCst);
        Ok(())
    }

    fn stop_recording(&self) -> Result<(), &'static str> {
        if !self.is_recording.load(Ordering::SeqCst) {
            return Err("Not recording!");
        }
        self.is_recording.store(false, Ordering::SeqCst);
        Ok(())
    }

    fn update_player_health(&self, new_health: i32) -> Result<i32, &'static str> {
        if !self.is_recording.load(Ordering::SeqCst) {
            return Err("Cannot change state when not recording.");
        }
        let mut state = self.state.lock().unwrap();
        if new_health < 0 {
            return Err("Health cannot be negative.");
        }
        state.health = new_health;
        Ok(state.health)
    }
}

use std::sync::{Mutex, Arc};
use std::thread;

struct ReplayState {
    recording_active: bool,
    frame_count: u64,
}
fn main() {
    let state = Arc::new(Mutex::new(ReplayState { recording_active: true, frame_count: 0 }));

    let state_clone_writer = Arc::clone(&state);
    let writer_handle = thread::spawn(move || {
        for i in 1..=5 {
            match state_clone_writer.lock() {
                Ok(mut state) => {
                    println!("Writer: Locked successfully. Updating frame to {}", i);
                    state.frame_count = i as u64;
                    thread::sleep(std::time::Duration::from_millis(10));
                },
                Err(e) => {
                    eprintln!("Writer: Failed to acquire lock: {}", e);
                }
            }
        }
    });

    let state_clone_reader = Arc::clone(&state);
    let reader_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(30));
        match state_clone_reader.lock() {
            Ok(state) => {
                println!("Reader: Locked successfully. Current frame count is {}", state.frame_count);
            },
            Err(e) => {
                eprintln!("Reader: Failed to acquire lock: {}", e);
            }
        }
    });

    writer_handle.join().unwrap();
    reader_handle.join().unwrap();
}
